    required init?(coder: NSCoder) {
        fatalError("init(coder:) is not supported")
    }

    deinit {
        displayTimer?.invalidate()
    }

    private func setupViews() {
        metalView.translatesAutoresizingMaskIntoConstraints = false
        addSubview(metalView)
        NSLayoutConstraint.activate([
            metalView.topAnchor.constraint(equalTo: topAnchor),
            metalView.bottomAnchor.constraint(equalTo: bottomAnchor),
            metalView.leadingAnchor.constraint(equalTo: leadingAnchor),
            metalView.trailingAnchor.constraint(equalTo: trailingAnchor),
        ])
    }

    func attach(session: TerminalSession) {
        self.session = session

        guard let metalLayer = metalView.metalLayer else {
            NSLog("TerminalPaneView: no Metal layer available, bounds=\(bounds), metalView.bounds=\(metalView.bounds)")
            return
        }
        NSLog("TerminalPaneView: attaching, bounds=\(bounds), metalLayer.bounds=\(metalLayer.bounds)")

        renderer = RendererHandle(
            layer: metalLayer,
            shell: session.shell,
            cwd: session.initialCwd,
            cols: session.cols,
            rows: session.rows
        )

        if renderer == nil {
            NSLog("TerminalPaneView: failed to create renderer")
        } else {
            let scale = Float(window?.backingScaleFactor ?? 2.0)
            renderer?.resize(
                width: Float(bounds.width),
                height: Float(bounds.height),
                scaleFactor: scale
            )
            startDisplayTimer()
        }
    }

    var frameCount = 0
    private func startDisplayTimer() {
        NSLog("TerminalPaneView: starting display timer")
        displayTimer?.invalidate()
        // 120fps = 1/120 = 0.00833s
        displayTimer = Timer.scheduledTimer(withTimeInterval: 1.0 / 120.0, repeats: true) { [weak self] _ in
            guard let self else { return }
            self.renderer?.drawFrame()
            self.frameCount += 1
            if self.frameCount == 1 || self.frameCount == 60 {
                NSLog("TerminalPaneView: frame \(self.frameCount), bounds=\(self.bounds), superview=\(self.superview != nil), window=\(self.window != nil)")
            }
        }
        // Ensure timer fires during tracking (mouse drag, resize, etc.)
        if let timer = displayTimer {
            RunLoop.main.add(timer, forMode: .common)
        }
    }

    // MARK: - Layout

    override func resizeSubviews(withOldSize oldSize: NSSize) {
        super.resizeSubviews(withOldSize: oldSize)
        notifyRendererOfResize()
    }

    /// Called by TerminalPortal after repositioning this view.
    func portalDidResize() {
        notifyRendererOfResize()
    }

    private func notifyRendererOfResize() {
        guard bounds.width > 0, bounds.height > 0 else { return }
        let scale = Float(window?.backingScaleFactor ?? 2.0)
        renderer?.resize(
            width: Float(bounds.width),
            height: Float(bounds.height),
            scaleFactor: scale
        )
    }

    // MARK: - Keyboard Input

    override var acceptsFirstResponder: Bool { true }
    override var canBecomeKeyView: Bool { true }

    override func keyDown(with event: NSEvent) {
        let chars = event.characters
        let flags = event.modifierFlags.rawValue
        renderer?.keyEvent(characters: chars, modifierFlags: UInt64(flags))
    }

    // MARK: - Mouse Input

    override func mouseDown(with event: NSEvent) {
        window?.makeFirstResponder(self)
    }

    override func scrollWheel(with event: NSEvent) {
        // TODO: Forward to renderer for scrollback
    }

    // MARK: - Paste

    @objc func paste(_ sender: Any?) {
        guard let text = NSPasteboard.general.string(forType: .string) else { return }
        renderer?.paste(text)
    }
}
